app.controller("Musician",function($scope,$http){$scope.fullScreen=false;$scope.imgName="/field_small.jpg";$scope.placeholderImage="/field_small.jpg";$scope.loadPlaceholderImage=function(){$http({method:"POST",url:"/ajax",data:{command:"get_user_settings"}}).then(function success(respond){if(respond.data&&respond.data.placeholder_image){$scope.placeholderImage=respond.data.placeholder_image}else{$scope.placeholderImage="/field_small.jpg"}},function error(erespond){$scope.placeholderImage="/field_small.jpg"})};$scope.checkImage=function(){$http({method:"POST",url:"/ajax",data:{command:"get_image"}}).then(function success(respond){if(respond.data.length>0){var imagePath=respond.data[0].image||"";var isSermonImage=imagePath.indexOf("/sermon_images/")===0;var isBible=imagePath==="__bible__";var isEmpty=imagePath==="";if(isSermonImage||isBible||isEmpty){$scope.imgName=$scope.placeholderImage}else{$scope.imgName=imagePath+"?t="+(new Date).getTime()}}else{$scope.imgName=$scope.placeholderImage}})};$scope.toggleFullscreen=function(){if(!$scope.fullScreen){document.getElementById("img0").requestFullscreen();$scope.fullScreen=true}else{if(document.exitFullscreen){document.exitFullscreen();$scope.fullScreen=false}}};function initSocket(){const socket=window.createAuthenticatedWebSocket(null,function(data){if(data.type==="update_needed"){$scope.$apply(function(){$scope.checkImage()})}},function(error){console.error("WebSocket error:",error)});socket.addEventListener("close",function(event){console.log("WebSocket closed, reconnecting in 2s...");setTimeout(initSocket,2e3)})}$scope.loadPlaceholderImage();$scope.checkImage();initSocket()});